package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;
import org.mockito.invocation.InvocationOnMock;
import org.mockito.stubbing.Answer;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

public class CSVFormatTest {

    @Test
    public void testWithHeader() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        String[] header = {"Name", "Age", "City"};

        // When
        Method method = CSVFormat.class.getDeclaredMethod("withHeader", String[].class);
        method.setAccessible(true);
        CSVFormat result = (CSVFormat) method.invoke(csvFormat, (Object) header);

        // Then
        assertNotNull(result);
        assertArrayEquals(header, result.getHeader());
    }
}
